  ('elementary-10ced7e2-moex-00362', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '有關訴願制度目的及運作的敘述，下列何者錯誤？', '["實踐憲法上人民之訴願權", "維護人民權益", "人民不服經聽證程序所為之行政處分，應先提起訴願，再提起行政訴訟", "係屬行政機關自我審查之機制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
