  ('elementary-10ced7e2-moex-00364', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '人民提起下列何種類型之行政訴訟，應先踐行訴願程序？', '["確認訴訟及一般給付訴訟", "課予義務訴訟及確認訴訟", "撤銷訴訟及課予義務訴訟", "課予義務訴訟及一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00365', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於簡易訴訟上訴程序之敘述，何者正確？', '["對於簡易程序之第一審判決，得上訴於管轄之地方法院，其審判以獨任行之", "對於簡易訴訟程序之第二審判決，當事人得逕向最高法院提起上訴，無上訴利益額數之限制", "對於簡易訴訟程序之第二審判決，提起第三審上訴，不須經原裁判法院之許可", "簡易訴訟程序第三審之性質，為法律審"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00366', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟當事人能力之敘述，何者正確？', '["關於遺產分割訴訟，得列同為繼承人之胎兒為被告，除非將來胎兒係死產，否則胎兒具當事人能力", "公寓大廈管理委員會無當事人能力，不得作為訴訟上之原告", "獨資商號具有當事人能力，得作為民事訴訟之當事人", "若原告於訴訟進行中死亡，法院應逕以原告無當事人能力，裁定駁回原告之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00367', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於民事程序上公開審理原則之適用，下列敘述，何者錯誤？', '["民事督促程序，原則上不適用公開審理原則", "關於非訟事件之關係人、證人、鑑定人之訊問，並非以公開審理為原則", "於普通訴訟程序，法院為審理時，得經兩造合意，而不進行公開審理", "遺產分割請求事件之審理，均應適用公開審理原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00368', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲家住臺東，於連假期間騎機車至屏東遊玩，行經墾丁時，汽車臨停於路旁之駕駛乙（家住臺中）突開車 門，甲閃避不及，因此而身受重傷。甲若欲起訴向乙請求民事損害賠償，其得向何法院提起訴訟？', '["僅得向臺灣臺東地方法院起訴", "僅得向臺灣屏東地方法院起訴", "得向臺灣臺中地方法院或臺灣屏東地方法院起訴", "得向臺灣臺東地方法院或臺灣屏東地方法院起訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00369', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲向乙借款新臺幣（下同）100萬元，由丙為保證人，其後因甲投資失利，無法清償借款。下列關於該保 證契約之敘述，何者正確？', '["保證債務之範圍，以主債務100萬元為限，故丙無須對主債務之利息或甲未如期還款所致之違約金，負 保證之責", "由於丙向乙為清償後，得向甲求償，故即使乙未就甲之財產強制執行而直接向丙請求清償，丙不得拒絕", "乙得對於甲或丙，同時或先後請求全部或一部之給付", "丙得以甲對於乙之債權，主張抵銷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00370', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲與乙訂立買賣契約，係向乙購買A屋，雙方約定買賣價金新臺幣（下同）1,000萬元。乙將A屋交付於 甲使用後，尚未辦理所有權移轉登記，A屋即因地震而滅失。下列敘述，何者正確？', '["甲已取得A屋之占有，應給付乙1,000萬元", "甲尚未取得A屋之所有權，故無須給付乙買賣價金", "甲乙雙方應互相讓步，由甲給付乙500萬元", "由法院斟酌甲乙雙方之經濟狀況，決定甲給付金額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
